import { __decorate } from "tslib";
import { customElement } from 'lit/decorators';
import { LitElement, html, css } from 'lit';
let DescriptionElement = class DescriptionElement extends LitElement {
    render() {
        return html `<slot></slot>`;
    }
};
DescriptionElement.styles = css `
    :host{
        display: block;
        padding: 10px 0;
        font-style: italic;
    }
    `;
DescriptionElement = __decorate([
    customElement('description-element')
], DescriptionElement);
export { DescriptionElement };
